package com.treeeducation.ioas.system.operatorprofile; import com.treeeducation.ioas.common.*;import io.swagger.v3.oas.annotations.*;import io.swagger.v3.oas.annotations.tags.Tag;import org.springframework.data.domain.*;import org.springframework.web.bind.annotation.*; /** Operator profile APIs. */ @RestController @RequestMapping("/api/v1/operators") @Tag(name="Operator Profile",description="运营人员下拉与列表") public class OperatorProfileController{private final OperatorProfileRepository repo; public OperatorProfileController(OperatorProfileRepository repo){this.repo=repo;} @GetMapping("/options") @Operation(summary="运营人员下拉") public ApiResponse<java.util.List<OperatorProfileDtos.Response>> options(){return ApiResponse.ok(repo.findByEnabledTrueOrderByNameAsc().stream().map(OperatorProfileDtos::of).toList());} @GetMapping @Operation(summary="运营人员列表") public ApiResponse<PageResponse<OperatorProfileDtos.Response>> list(@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="20")int size){return ApiResponse.ok(PageResponse.of(repo.findAll(PageRequest.of(page,size)).map(OperatorProfileDtos::of)));}}
